1	/**
2	 * Public calibration scorecard — read-through layer.
3	 *
4	 * Source-of-truth precedence:
5	 *
6	 *   1. The nightly manifest written by `noosphere/forecasts/scheduler.py`
7	 *      (path resolved from THESEUS_PUBLIC_CALIBRATION_PATH or
8	 *      NOOSPHERE_DATA_DIR/public_calibration_manifest.json). Reading from
9	 *      the disk artifact is the auditable path: the same bytes that
10	 *      external auditors hash are the bytes the page renders.
11	 *
12	 *   2. Live DB fallback. If the manifest is not on disk (cold start, dev,
13	 *      no scheduler) we synthesize a partial manifest from Prisma. This
14	 *      is the lossy path — no method / domain attribution — but it lets
15	 *      the page render the aggregate Brier and reliability curve.
16	 *
17	 * All shaping (binning, bootstrap, hashing) happens in Python. This TS
18	 * file is a normalizer, not an estimator; it never recomputes the curve.
19	 */
20	
21	import { createHash } from "node:crypto";
22	import fs from "node:fs";
23	import path from "node:path";
24	
25	import { db } from "@/lib/db";
26	
27	export const PUBLIC_CALIBRATION_SCHEMA = "theseus.public_calibration.manifest";
28	export const PUBLIC_CALIBRATION_SCHEMA_VERSION = 1;
29	export const SPARSE_BIN_THRESHOLD = 5;
30	export const STALE_DAYS = 14;
31	
32	export type CalibrationFilter = {
33	  domain?: string | null;
34	  methodName?: string | null;
35	  methodVersion?: string | null;
36	};
37	
38	export type BrierWindow = {
39	  label: string;
40	  days: number | null;
41	  n: number;
42	  meanBrier: number | null;
43	  meanLogLoss: number | null;
44	};
45	
46	export type ReliabilityBin = {
47	  lo: number;
48	  hi: number;
49	  n: number;
50	  meanPredicted: number | null;
51	  observedFrequency: number | null;
52	  ciLow: number | null;
53	  ciHigh: number | null;
54	  sparse: boolean;
55	};
56	
57	export type CalibrationSlope = {
58	  slope: number | null;
59	  ciLow: number | null;
60	  ciHigh: number | null;
61	  sampleSize: number;
62	};
63	
64	export type DecileEntry = {
65	  predictionId: string;
66	  marketId: string;
67	  headline: string;
68	  marketTitle: string;
69	  marketUrl: string | null;
70	  domain: string;
71	  methodName: string | null;
72	  methodVersion: string | null;
73	  probabilityYes: number;
74	  outcome: string;
75	  brier: number;
76	  resolvedAt: string | null;
77	};
78	
79	export type MethodFacet = {
80	  name: string;
81	  version: string;
82	  n: number;
83	};
84	
85	export type PublicCalibrationManifest = {
86	  schema: string;
87	  schemaVersion: number;
88	  generatedAt: string;
89	  source: "manifest" | "live";
90	  publishHorizonDays: number;
91	  sparseBinThreshold: number;
92	  bootstrapIterations: number;
93	  ciLevel: number;
94	  binCount: number;
95	  counts: {
96	    total: number;
97	    resolvedBinary: number;
98	    withdrawn: number;
99	    staleUnresolved: number;
100	    continuous: number;
101	  };
102	  withdrawnRate: number | null;
103	  resolutionSetHash: string;
104	  binaryMetricName: string;
105	  continuousMetricName: string;
106	  aggregateBrier: BrierWindow[];
107	  calibrationCurve: ReliabilityBin[];
108	  calibrationSlope: CalibrationSlope;
109	  decileBest: DecileEntry[];
110	  decileWorst: DecileEntry[];
111	  continuousQuadraticLoss: number | null;
112	  domains: string[];
113	  methods: MethodFacet[];
114	  filter: CalibrationFilter;
115	  notes: string[];
116	};
117	
118	// ── Shared low-level helpers ──────────────────────────────────────────────
119	
120	function asNumber(value: unknown): number | null {
121	  if (value === null || value === undefined) return null;
122	  if (typeof value === "number") return Number.isFinite(value) ? value : null;
123	  if (typeof value === "string") {
124	    const trimmed = value.trim();
125	    if (!trimmed) return null;
126	    const n = Number(trimmed);
127	    return Number.isFinite(n) ? n : null;
128	  }
129	  if (typeof value === "object" && value !== null && "toNumber" in (value as object)) {
130	    try {
131	      const n = (value as { toNumber: () => number }).toNumber();
132	      return Number.isFinite(n) ? n : null;
133	    } catch {
134	      return null;
135	    }
136	  }
137	  return null;
138	}
139	
140	function asString(value: unknown, fallback = ""): string {
141	  if (value === null || value === undefined) return fallback;
142	  return String(value);
143	}
144	
145	function asBoolean(value: unknown): boolean {
146	  if (typeof value === "boolean") return value;
147	  if (typeof value === "string") return value.trim().toLowerCase() === "true";
148	  return Boolean(value);
149	}
150	
151	function isoOrNull(value: unknown): string | null {
152	  if (value === null || value === undefined) return null;
153	  if (value instanceof Date) return value.toISOString();
154	  if (typeof value === "string") return value || null;
155	  return null;
156	}
157	
158	function manifestPath(): string {
159	  const explicit = process.env.THESEUS_PUBLIC_CALIBRATION_PATH?.trim();
160	  if (explicit) return explicit;
161	  const dataDir = process.env.NOOSPHERE_DATA_DIR?.trim();
162	  const root = dataDir ? dataDir : "/var/lib/theseus";
163	  return path.join(root, "public_calibration_manifest.json");
164	}
165	
166	// ── Disk path: read the canonical nightly manifest ────────────────────────
167	
168	function readManifestFromDisk(): PublicCalibrationManifest | null {
169	  const file = manifestPath();
170	  let text: string;
171	  try {
172	    text = fs.readFileSync(file, "utf8");
173	  } catch {
174	    return null;
175	  }
176	  try {
177	    const raw = JSON.parse(text) as Record<string, unknown>;
178	    return normalizeManifest(raw, "manifest");
179	  } catch (err) {
180	    console.warn("[public calibration] manifest parse failed:", err);
181	    return null;
182	  }
183	}
184	
185	function normalizeManifest(
186	  raw: Record<string, unknown>,
187	  source: "manifest" | "live",
188	): PublicCalibrationManifest {
189	  const counts = (raw.counts ?? {}) as Record<string, unknown>;
190	  const filter = (raw.filter ?? {}) as Record<string, unknown>;
191	  const slope = (raw.calibration_slope ?? {}) as Record<string, unknown>;
192	
193	  return {
194	    schema: asString(raw.schema, PUBLIC_CALIBRATION_SCHEMA),
195	    schemaVersion: Number(raw.schema_version ?? PUBLIC_CALIBRATION_SCHEMA_VERSION),
196	    generatedAt: asString(raw.generated_at, new Date().toISOString()),
197	    source,
198	    publishHorizonDays: Number(raw.publish_horizon_days ?? STALE_DAYS),
199	    sparseBinThreshold: Number(raw.sparse_bin_threshold ?? SPARSE_BIN_THRESHOLD),
200	    bootstrapIterations: Number(raw.bootstrap_iterations ?? 0),
201	    ciLevel: Number(raw.ci_level ?? 0.9),
202	    binCount: Number(raw.bin_count ?? 10),
203	    counts: {
204	      total: Number(counts.total ?? 0),
205	      resolvedBinary: Number(counts.resolved_binary ?? 0),
206	      withdrawn: Number(counts.withdrawn ?? 0),
207	      staleUnresolved: Number(counts.stale_unresolved ?? 0),
208	      continuous: Number(counts.continuous ?? 0),
209	    },
210	    withdrawnRate: asNumber(raw.withdrawn_rate),
211	    resolutionSetHash: asString(raw.resolution_set_hash),
212	    binaryMetricName: asString(raw.binary_metric_name, "brier_score"),
213	    continuousMetricName: asString(raw.continuous_metric_name, "quadratic_loss"),
214	    aggregateBrier: ((raw.aggregate_brier ?? []) as Array<Record<string, unknown>>).map((w) => ({
215	      label: asString(w.label),
216	      days: w.days === null || w.days === undefined ? null : Number(w.days),
217	      n: Number(w.n ?? 0),
218	      meanBrier: asNumber(w.mean_brier),
219	      meanLogLoss: asNumber(w.mean_log_loss),
220	    })),
221	    calibrationCurve: ((raw.calibration_curve ?? []) as Array<Record<string, unknown>>).map((b) => ({
222	      lo: Number(b.lo ?? 0),
223	      hi: Number(b.hi ?? 0),
224	      n: Number(b.n ?? 0),
225	      meanPredicted: asNumber(b.mean_predicted),
226	      observedFrequency: asNumber(b.observed_frequency),
227	      ciLow: asNumber(b.ci_low),
228	      ciHigh: asNumber(b.ci_high),
229	      sparse: asBoolean(b.sparse),
230	    })),
231	    calibrationSlope: {
232	      slope: asNumber(slope.slope),
233	      ciLow: asNumber(slope.ci_low),
234	      ciHigh: asNumber(slope.ci_high),
235	      sampleSize: Number(slope.sample_size ?? 0),
236	    },
237	    decileBest: ((raw.decile_best ?? []) as Array<Record<string, unknown>>).map(normalizeDecile),
238	    decileWorst: ((raw.decile_worst ?? []) as Array<Record<string, unknown>>).map(normalizeDecile),
239	    continuousQuadraticLoss: asNumber(raw.continuous_quadratic_loss),
240	    domains: ((raw.domains ?? []) as unknown[]).map((d) => asString(d)).filter(Boolean),
241	    methods: ((raw.methods ?? []) as Array<Record<string, unknown>>).map((m) => ({
242	      name: asString(m.name),
243	      version: asString(m.version),
244	      n: Number(m.n ?? 0),
245	    })),
246	    filter: {
247	      domain: typeof filter.domain === "string" ? filter.domain : null,
248	      methodName: typeof filter.method_name === "string" ? filter.method_name : null,
249	      methodVersion: typeof filter.method_version === "string" ? filter.method_version : null,
250	    },
251	    notes: ((raw.notes ?? []) as unknown[]).map((n) => asString(n)).filter(Boolean),
252	  };
253	}
254	
255	function normalizeDecile(raw: Record<string, unknown>): DecileEntry {
256	  return {
257	    predictionId: asString(raw.prediction_id),
258	    marketId: asString(raw.market_id),
259	    headline: asString(raw.headline),
260	    marketTitle: asString(raw.market_title),
261	    marketUrl: typeof raw.market_url === "string" ? raw.market_url : null,
262	    domain: asString(raw.domain),
263	    methodName: typeof raw.method_name === "string" ? raw.method_name : null,
264	    methodVersion: typeof raw.method_version === "string" ? raw.method_version : null,
265	    probabilityYes: Number(raw.probability_yes ?? 0),
266	    outcome: asString(raw.outcome),
267	    brier: Number(raw.brier ?? 0),
268	    resolvedAt: typeof raw.resolved_at === "string" ? raw.resolved_at : null,
269	  };
270	}
271	
272	// ── Live fallback: read directly from Prisma when no manifest is on disk ──
273	
274	function marketUrl(source: string, externalId: string | null): string | null {
275	  if (!externalId) return null;
276	  if (source === "POLYMARKET") return `https://polymarket.com/event/${externalId}`;
277	  if (source === "KALSHI") return `https://kalshi.com/markets/${externalId}`;
278	  return null;
279	}
280	
281	type LiveRow = {
282	  predictionId: string;
283	  marketId: string;
284	  headline: string;
285	  marketTitle: string;
286	  marketUrl: string | null;
287	  domain: string;
288	  probabilityYes: number;
289	  outcome: string;
290	  brier: number;
291	  logLoss: number | null;
292	  resolvedAt: Date;
293	  publishedAt: Date;
294	};
295	
296	async function buildLiveManifest(filter: CalibrationFilter): Promise<PublicCalibrationManifest> {
297	  const predictions = await db.forecastPrediction.findMany({
298	    where: { status: "PUBLISHED" },
299	    include: {
300	      market: true,
301	      resolution: true,
302	    },
303	    take: 5000,
304	    orderBy: { createdAt: "desc" },
305	  });
306	
307	  const liveRows: LiveRow[] = [];
308	  let withdrawn = 0;
309	  let staleUnresolved = 0;
310	  const now = Date.now();
311	  const staleCutoff = now - STALE_DAYS * 86_400_000;
312	  for (const pred of predictions) {
313	    const market = pred.market;
314	    const resolution = pred.resolution;
315	    const domain = asString(market?.category ?? "", "");
316	    if (filter.domain && filter.domain !== domain) continue;
317	    if (resolution && resolution.marketOutcome === "CANCELLED") {
318	      withdrawn += 1;
319	      continue;
320	    }
321	    if (!resolution) {
322	      const ageMs = now - pred.createdAt.getTime();
323	      if (ageMs >= STALE_DAYS * 86_400_000) staleUnresolved += 1;
324	      continue;
325	    }
326	    if (resolution.marketOutcome !== "YES" && resolution.marketOutcome !== "NO") continue;
327	    const probability = asNumber(pred.probabilityYes);
328	    const brier = asNumber(resolution.brierScore);
329	    if (probability === null || brier === null) continue;
330	    liveRows.push({
331	      predictionId: pred.id,
332	      marketId: pred.marketId,
333	      headline: pred.headline,
334	      marketTitle: market?.title ?? pred.headline,
335	      marketUrl: market ? marketUrl(market.source, market.externalId) : null,
336	      domain,
337	      probabilityYes: probability,
338	      outcome: resolution.marketOutcome,
339	      brier,
340	      logLoss: asNumber(resolution.logLoss),
341	      resolvedAt: resolution.resolvedAt,
342	      publishedAt: pred.createdAt,
343	    });
344	    void staleCutoff; // keep for reference; the loop above counts via age
345	  }
346	
347	  const aggregateBrier = computeAggregateBrierLive(liveRows, now);
348	  const decileBest = liveRows
349	    .slice()
350	    .sort((a, b) => a.brier - b.brier)
351	    .slice(0, 10)
352	    .map(toDecileEntry);
353	  const decileWorst = liveRows
354	    .slice()
355	    .sort((a, b) => b.brier - a.brier)
356	    .slice(0, 10)
357	    .map(toDecileEntry);
358	
359	  const denom = liveRows.length + withdrawn;
360	  const withdrawnRate = denom > 0 ? withdrawn / denom : null;
361	  const resolutionSetHash = liveResolutionHash(liveRows);
362	
363	  const notes: string[] = [
364	    "Live fallback: nightly calibration manifest is not on disk. Method / domain attribution and bootstrap CIs are not available until the scheduler runs.",
365	  ];
366	  if (staleUnresolved > 0) {
367	    notes.push(`${staleUnresolved} forecasts are unresolved-but-stale; flagged, not dropped.`);
368	  }
369	  if (withdrawn > 0) {
370	    notes.push(
371	      `${withdrawn} forecasts are withdrawn or revoked. Excluded from calibration metrics; counted toward the withdrawn rate.`,
372	    );
373	  }
374	
375	  const domains = Array.from(new Set(liveRows.map((r) => r.domain).filter(Boolean))).sort();
376	
377	  return {
378	    schema: PUBLIC_CALIBRATION_SCHEMA,
379	    schemaVersion: PUBLIC_CALIBRATION_SCHEMA_VERSION,
380	    generatedAt: new Date().toISOString(),
381	    source: "live",
382	    publishHorizonDays: STALE_DAYS,
383	    sparseBinThreshold: SPARSE_BIN_THRESHOLD,
384	    bootstrapIterations: 0,
385	    ciLevel: 0.9,
386	    binCount: 0,
387	    counts: {
388	      total: liveRows.length + withdrawn + staleUnresolved,
389	      resolvedBinary: liveRows.length,
390	      withdrawn,
391	      staleUnresolved,
392	      continuous: 0,
393	    },
394	    withdrawnRate,
395	    resolutionSetHash,
396	    binaryMetricName: "brier_score",
397	    continuousMetricName: "quadratic_loss",
398	    aggregateBrier,
399	    calibrationCurve: [],
400	    calibrationSlope: {
401	      slope: null,
402	      ciLow: null,
403	      ciHigh: null,
404	      sampleSize: liveRows.length,
405	    },
406	    decileBest,
407	    decileWorst,
408	    continuousQuadraticLoss: null,
409	    domains,
410	    methods: [],
411	    filter: {
412	      domain: filter.domain ?? null,
413	      methodName: filter.methodName ?? null,
414	      methodVersion: filter.methodVersion ?? null,
415	    },
416	    notes,
417	  };
418	}
419	
420	function toDecileEntry(row: LiveRow): DecileEntry {
421	  return {
422	    predictionId: row.predictionId,
423	    marketId: row.marketId,
424	    headline: row.headline,
425	    marketTitle: row.marketTitle,
426	    marketUrl: row.marketUrl,
427	    domain: row.domain,
428	    methodName: null,
429	    methodVersion: null,
430	    probabilityYes: row.probabilityYes,
431	    outcome: row.outcome,
432	    brier: row.brier,
433	    resolvedAt: isoOrNull(row.resolvedAt),
434	  };
435	}
436	
437	function computeAggregateBrierLive(rows: LiveRow[], nowMs: number): BrierWindow[] {
438	  const windows: Array<{ label: string; days: number | null }> = [
439	    { label: "all-time", days: null },
440	    { label: "30d", days: 30 },
441	    { label: "90d", days: 90 },
442	    { label: "365d", days: 365 },
443	  ];
444	  return windows.map(({ label, days }) => {
445	    const cutoff = days === null ? -Infinity : nowMs - days * 86_400_000;
446	    const bucket = rows.filter((r) => r.resolvedAt.getTime() >= cutoff);
447	    const briers = bucket.map((r) => r.brier);
448	    const losses = bucket.map((r) => r.logLoss).filter((v): v is number => v !== null);
449	    return {
450	      label,
451	      days,
452	      n: bucket.length,
453	      meanBrier: briers.length > 0 ? briers.reduce((a, b) => a + b, 0) / briers.length : null,
454	      meanLogLoss: losses.length > 0 ? losses.reduce((a, b) => a + b, 0) / losses.length : null,
455	    };
456	  });
457	}
458	
459	function round12(value: number): number {
460	  return Number(value.toPrecision(12));
461	}
462	
463	function liveResolutionHash(rows: LiveRow[]): string {
464	  const sorted = rows.slice().sort((a, b) => a.predictionId.localeCompare(b.predictionId));
465	  const payload = sorted.map((r) => ({
466	    id: r.predictionId,
467	    p: round12(r.probabilityYes),
468	    o: r.outcome,
469	    t: r.resolvedAt.toISOString().replace(".000Z", "Z"),
470	    b: round12(r.brier),
471	  }));
472	  const canon = JSON.stringify(payload);
473	  return createHash("sha256").update(canon, "utf8").digest("hex");
474	}
475	
476	// ── Filtering ─────────────────────────────────────────────────────────────
477	
478	function applyFilter(
479	  manifest: PublicCalibrationManifest,
480	  filter: CalibrationFilter,
481	): PublicCalibrationManifest {
482	  const isFiltered = Boolean(filter.domain || filter.methodName || filter.methodVersion);
483	  if (!isFiltered) return manifest;
484	  // Only the decile views are easy to re-filter client-side without
485	  // re-running bootstrap. For a real per-method drill-down, the manifest
486	  // already exposes the filter slot — the Python build_manifest is the
487	  // authoritative path. Until a per-method manifest is published, we
488	  // return the unfiltered curve with the filter recorded so the page can
489	  // render a "filter pending" notice.
490	  const matchEntry = (e: DecileEntry): boolean => {
491	    if (filter.domain && e.domain !== filter.domain) return false;
492	    if (filter.methodName && e.methodName !== filter.methodName) return false;
493	    if (filter.methodVersion && e.methodVersion !== filter.methodVersion) return false;
494	    return true;
495	  };
496	  return {
497	    ...manifest,
498	    filter: {
499	      domain: filter.domain ?? null,
500	      methodName: filter.methodName ?? null,
501	      methodVersion: filter.methodVersion ?? null,
502	    },
503	    decileBest: manifest.decileBest.filter(matchEntry),
504	    decileWorst: manifest.decileWorst.filter(matchEntry),
505	    notes: [
506	      ...manifest.notes,
507	      "Filter applied to decile views only. Aggregate Brier and reliability curve are the all-cohort numbers from the published manifest.",
508	    ],
509	  };
510	}
511	
512	// ── Public entry points ───────────────────────────────────────────────────
513	
514	export async function loadPublicCalibrationManifest(
515	  filter: CalibrationFilter = {},
516	): Promise<PublicCalibrationManifest> {
517	  const fromDisk = readManifestFromDisk();
518	  if (fromDisk) return applyFilter(fromDisk, filter);
519	  const live = await buildLiveManifest(filter);
520	  return live;
521	}
522	
523	export function manifestPathForTests(): string {
524	  return manifestPath();
525	}
526

