1	import { NextResponse } from "next/server";
2	import type { NextRequest } from "next/server";
3	
4	import {
5	  type CalibrationFilter,
6	  loadPublicCalibrationManifest,
7	} from "@/lib/calibrationData";
8	import { publicCorsHeaders } from "@/lib/publicCors";
9	
10	export const runtime = "nodejs";
11	export const dynamic = "force-dynamic";
12	
13	/**
14	 * Public calibration manifest endpoint.
15	 *
16	 * Returns the full data backing `/calibration` so external auditors can
17	 * verify the published numbers without running the firm's tooling.
18	 * Schema is versioned via the top-level `schemaVersion` field — pin
19	 * against it.
20	 *
21	 * Honest-by-construction: includes the SHA-256 `resolutionSetHash` over
22	 * the canonicalized resolved-prediction set. The same hash that appears
23	 * on the page appears here, so a discrepancy is detectable.
24	 *
25	 * Optional filters (URL query params): `domain`, `method`, `version`.
26	 * Filters narrow the decile views; aggregate Brier and the reliability
27	 * curve come from the published nightly manifest as-is so the public
28	 * cohort cannot be sliced into vanity subsets without leaving a trail.
29	 */
30	export function OPTIONS(req: NextRequest) {
31	  const headers = new Headers(publicCorsHeaders(req));
32	  headers.set("Access-Control-Allow-Methods", "GET, OPTIONS");
33	  return new NextResponse(null, { status: 204, headers });
34	}
35	
36	export async function GET(req: NextRequest) {
37	  const corsHeaders = new Headers(publicCorsHeaders(req));
38	  corsHeaders.set("Access-Control-Allow-Methods", "GET, OPTIONS");
39	  const url = new URL(req.url);
40	  const filter: CalibrationFilter = {
41	    domain: url.searchParams.get("domain"),
42	    methodName: url.searchParams.get("method"),
43	    methodVersion: url.searchParams.get("version"),
44	  };
45	  try {
46	    const manifest = await loadPublicCalibrationManifest(filter);
47	    const headers = new Headers(corsHeaders);
48	    headers.set("Cache-Control", "public, max-age=60, s-maxage=300");
49	    headers.set("Content-Type", "application/json");
50	    headers.set("X-Resolution-Set-Hash", manifest.resolutionSetHash);
51	    headers.set("X-Schema-Version", String(manifest.schemaVersion));
52	    return NextResponse.json(manifest, { status: 200, headers });
53	  } catch (error) {
