// ── ContradictionFinding + scores — mirrors pipeline outputs ────────────────

model Contradiction {
  id             String @id @default(cuid())
  organizationId String

  claimAId     String
  claimBId     String
  severity     Float
  sixLayerJson String?
  narrative    String   @default("")
  createdAt    DateTime @default(now())

  // ── Source tracking ───────────────────────────────────────────────
  // The upload whose ingestion run produced this contradiction row.
  // Nullable so the column can be backfilled from `noosphereId` patterns
  // on existing rows; the ingest pipeline sets it on every new row.
  // When the source upload is deleted the contradiction is hard-deleted
  // in the same transaction (see src/app/api/upload/[id]/delete/route.ts);
  // cross-upload contradictions (where claimA and claimB come from
  // different uploads) additionally die if EITHER of their referenced
  // Conclusions has already been orphan-deleted.
  sourceUploadId String?
  sourceUpload   Upload? @relation("ContradictionSourceUpload", fields: [sourceUploadId], references: [id])

  // ── Resolution tracking ────────────────────────────────────────────
  // A contradiction starts "active". A founder can resolve it
  // (acknowledged + addressed with a note) or dismiss it (false
  // positive). Non-active rows are hidden from the main view by
  // default but preserved for audit.
  status       String    @default("active") // active | resolved | dismissed
  resolution   String?
  resolvedById String?
  resolvedAt   DateTime?
  resolvedBy   Founder?  @relation("ContradictionResolver", fields: [resolvedById], references: [id])

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([sourceUploadId])
  @@index([status])
